<?php
/** Expense transaction detail. */
declare(strict_types=1);require_once __DIR__.'/../../config/config.php';requireAuth();enforceModuleAccess('expenses');$s=getDb()->prepare('SELECT e.*,v.registration_number,t.trip_number,c.name category_name FROM expenses e LEFT JOIN vehicles v ON v.id=e.vehicle_id LEFT JOIN trips t ON t.id=e.trip_id LEFT JOIN expense_categories c ON c.id=e.expense_category_id WHERE e.id=?');$s->execute([(int)($_GET['id']??0)]);$e=$s->fetch();if(!$e){setFlash('danger','Expense not found.');redirect('modules/expenses/index.php');}$pageTitle='Expense';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';?><main class="main-content expense-module"><?php require ROOT_PATH.'/includes/navbar.php';?><article class="card dashboard-card"><h1 class="page-title"><?=e($e['title'])?></h1><dl class="profile-list"><dt>Amount</dt><dd><?=e(formatCurrency((float)$e['amount']))?></dd><dt>Category</dt><dd><?=e($e['category_name']?:$e['expense_type'])?></dd><dt>Vehicle</dt><dd><?=e($e['registration_number']?:'—')?></dd><dt>Trip</dt><dd><?=e($e['trip_number']?:'—')?></dd><dt>Vendor</dt><dd><?=e($e['vendor_name']?:'—')?></dd><dt>Date</dt><dd><?=e(formatDate($e['expense_date']))?></dd></dl><p><?=e($e['description']?:'No description provided.')?></p></article></main><?php require ROOT_PATH.'/includes/footer.php';?>
